# dags/dag_factory.py
import yaml
from airflow.decorators import dag, task
from datetime import datetime

with open('/opt/airflow/dags/pipelines.yaml') as f:
    pipelines = yaml.safe_load(f)

def create_dag(config):
    @dag(dag_id=config['dag_id'], schedule=config.get('schedule', '@daily'),
         start_date=datetime(2026, 1, 1), catchup=False, tags=config.get('tags', []))
    def generated():
        @task
        def extract(ds_nodash=None):
            return {'path': f"s3://raw/{config['source']}/{ds_nodash}/"}
        @task
        def validate(meta: dict):
            return meta
        @task
        def load(meta: dict):
            return {'status': 'loaded'}
        load(validate(extract()))
    return generated()

for p in pipelines:
    globals()[p['dag_id']] = create_dag(p)

TEMPLATES = {
    'sftp_ingest': sftp_ingest_template,
    'api_pull': api_pull_template,
}

def create_dag(config):
    template_fn = TEMPLATES[config.get('template', 'sftp_ingest')]
    @dag(dag_id=config['dag_id'], ...)
    def generated():
        template_fn(config)
    return generated()

def test_factory_creates_dag():
    config = {'dag_id': 'test_meters', 'source': 'meters', 'country': 'DE'}
    dag = create_dag(config)
    assert dag.dag_id == 'test_meters'

